import Link from '@kyokuya/react-link'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React, { useMemo } from 'react'

export interface PaginationProps {
  /**
   * Current page number.
   */
  current: number
  /**
   * Count of total pages.
   */
  totalPage: number
  /**
   * Pagination url prefix.
   */
  resolveUrl(pageNo: number): string | null
}

export const Pagination: React.FC<PaginationProps> = props => {
  const { current, totalPage, resolveUrl } = props
  const pagination = useMemo<React.ReactElement>(() => {
    const firstPageUrl: string = resolveUrl(1)!
    const prevPageUrl: string | null = resolveUrl(current - 1)
    const nextPageUrl: string | null = resolveUrl(current + 1)
    const lastPageUrl: string = resolveUrl(totalPage)!

    const minimumPageNo = Math.max(1, current - 3)
    const maximumPageNo = Math.min(totalPage, current + 3)
    const paginationBtns: React.ReactNode[] = []
    for (let i = minimumPageNo; i <= maximumPageNo; ++i) {
      paginationBtns.push(
        <li
          key={i}
          className={cn('kyokuya-post-pagination__item', {
            'kyokuya-post-pagination__item--active': i === current,
          })}
        >
          <Link url={resolveUrl(i)!}>{i}</Link>
        </li>,
      )
    }

    return (
      <ul className="kyokuya-post-pagination">
        {prevPageUrl != null && (
          <li key="prev" className="kyokuya-post-pagination__item">
            <Link key="first-page" url={firstPageUrl}>
              «
            </Link>
            <Link key="prev-page" url={prevPageUrl}>
              Prev
            </Link>
            &nbsp;&nbsp;
          </li>
        )}
        {paginationBtns}
        {nextPageUrl != null && (
          <li key="next" className="kyokuya-post-pagination__item">
            &nbsp;&nbsp;
            <Link key="first-page" url={nextPageUrl}>
              Next
            </Link>
            <Link key="last-page" url={lastPageUrl}>
              »
            </Link>
          </li>
        )}
      </ul>
    )
  }, [current, totalPage, resolveUrl])
  return pagination
}

Pagination.propTypes = {
  current: PropTypes.number.isRequired,
  totalPage: PropTypes.number.isRequired,
  resolveUrl: PropTypes.func.isRequired,
}

Pagination.displayName = 'KyokuyaLayoutPostPagination'
export default Pagination
