import type { MagicPanelContentType, PostItem } from './types'

export enum PostLayoutActionsType {
  // Emit a search request.
  SEARCH_REQUEST = '@kyokuya/search/request',

  // Refresh the static data.
  REFRESH_STATIC_DATA = '@kyokuya/refresh/static-data',

  // Active a magic panel
  ACTIVE_MAGIC_PANEL = '@kyokuya/magic-panel/active',

  // Toggle magic panel.
  TOGGLE_MAGIC_PANEL = '@kyokuya/magic-panel/toggle',

  // Change brightness
  TOGGLE_THEME_BRIGHTNESS = '@kyokuya/theme/toggle-brightness',

  // Change brightness with preset brightnesses.
  TOGGLE_THEME_MODE = '@kyokuya/theme/toggle-mode',
}

export type PostLayoutAction =
  | {
      type: PostLayoutActionsType.SEARCH_REQUEST
      payload: { keyword: string }
    }
  | {
      type: PostLayoutActionsType.TOGGLE_MAGIC_PANEL
      payload?: boolean
    }
  | {
      type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL
      payload: { panel: MagicPanelContentType }
    }
  | {
      type: PostLayoutActionsType.REFRESH_STATIC_DATA
      payload: {
        tags: ReadonlyArray<string>
        posts: ReadonlyArray<PostItem>
      }
    }
  | {
      type: PostLayoutActionsType.TOGGLE_THEME_BRIGHTNESS
      payload: number
    }
  | {
      type: PostLayoutActionsType.TOGGLE_THEME_MODE
      payload?: 'darken' | 'light'
    }
